<div class="card form-card-narrow"><h3>Mobile Recharge</h3><form method="post" action="<?= base_url('index.php?route=wallet/recharge/submit') ?>"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><div class="form-group"><label>Operator</label><select name="operator_id" required><option value="">Select operator</option><?php foreach ($operators as $operator): ?><option value="<?= (int)$operator['id'] ?>"><?= e($operator['name']) ?></option><?php endforeach; ?></select></div><div class="form-group"><label>Phone Number</label><input type="text" name="phone_number" required></div><div class="form-group"><label>Amount</label><input type="number" step="0.01" min="1" name="amount" required></div><button class="btn btn-primary" type="submit">Recharge Now</button></form></div>
